package com.i2i.voltwise.audit; import com.i2i.voltwise.home.Home; import jakarta.persistence.*; import java.time.Instant; @Entity @Table(name="audit_events") public class AuditEvent { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) public Long id; @ManyToOne(optional=false,fetch=FetchType.LAZY) @JoinColumn(name="home_id") public Home home; @Column(name="event_type",nullable=false) public String eventType; @Column(nullable=false,columnDefinition="text") public String details; @Column(name="created_at",nullable=false) public Instant createdAt; protected AuditEvent(){} public AuditEvent(Home h,String type,String details){home=h;eventType=type;this.details=details;createdAt=Instant.now();} }
